In case anyone is having the same issue, here's how I solved it:

```
from xmltodict import parse

@csrf.exempt
@app.route('/login/', methods=['POST'])
def cas_logout():
    if request.form.get('logoutRequest'):
        logout_request = parse(request.form['logoutRequest'])
        ticket = logout_request.get('samlp:LogoutRequest', {}).get('samlp:SessionIndex')
        # get corresponding session and invalidate it
        if ticket:
            sess = r.get(ticket)
            if sess:
                r.delete(sess)
                r.delete(ticket)
                return 'OK'
    return 'Bad Request', 400
```

